def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_score = 0
        if ratio < 0.2:
            base_score = (1 - ratio)**4 + np.sin(2 * ratio * np.pi)
        elif 0.2 <= ratio < 0.4:
            base_score = np.log1p(ratio * 3) * 2 - ratio**2
        elif 0.4 <= ratio < 0.7:
            base_score = 0.5 / (1 + np.exp(-20 * (ratio - 0.55))) + np.cos(3 * ratio * np.pi)
        elif 0.7 <= ratio < 1.0:
            base_score = np.tanh(15 * (ratio - 0.8)) + 0.7
        else:
            base_score = 2 - ratio
        penalty = 0
        for j in range(1, 8):
            mod_val = (item * j) % capacity
            frac = mod_val / (capacity * j)
            if frac < 0.15:
                penalty += frac**1.5 * (j / 2)
            elif 0.15 <= frac < 0.4:
                penalty += np.sqrt(frac) * (j / 3)
            else:
                penalty += frac / (j**2)
            if j % 2 == 0 and penalty > j * 0.1:
                penalty -= 0.05 * j
        extra_penalty = 0
        decrement = 1
        for k in range(1, 6):
            threshold = 0.4 * k
            if ratio > threshold:
                extra_penalty += np.exp(-k * ratio) * (k + 0.5)
            else:
                extra_penalty += (np.log1p(k * ratio + 1)**0.5) / (k + 2)
            if k % 3 == 0:
                decrement *= 0.9
            else:
                decrement *= 1.05
        interaction_factor = 0
        for m in range(1, 5):
            for n in range(m, 7):
                diff = abs((item * m) % (capacity + n) - (capacity * n) % (item + m))
                interaction_factor += np.sin(diff / (capacity + item + m + n) * np.pi)
            interaction_factor /= (m + 1)
        if capacity % 3 == 0:
            priorities[i] = base_score + penalty * 1.2 * decrement + extra_penalty * 0.85 + interaction_factor * 0.1
        elif capacity % 5 == 0:
            priorities[i] = base_score + penalty * 0.9 * decrement + extra_penalty + interaction_factor * 0.2
        else:
            priorities[i] = base_score + penalty * decrement + extra_penalty * 0.75 + interaction_factor * 0.15
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
